// Auto-filter: only show events from today onwards — sorted chronologically
const _MOIS = {jan:0,fév:1,mar:2,avr:3,mai:4,juin:5,juil:6,août:7,sep:8,oct:9,nov:10,déc:11};
function _eventDate(e) {
  const p = e.date.trim().split(' ');
  const m = _MOIS[p[2]];
  return m !== undefined ? new Date(e.year || new Date().getFullYear(), m, parseInt(p[1])) : null;
}
const _today = new Date(); _today.setHours(0, 0, 0, 0);
function _eventHour(e) {
  const m = (e.time || '').replace(/\s/g,'').match(/^(\d{1,2})h(\d{2})?/);
  return m ? parseInt(m[1]) * 60 + (m[2] ? parseInt(m[2]) : 0) : 9999;
}

export const ALL_EVENTS = _RAW
  .filter(e => { const d = _eventDate(e); return d && d >= _today; })
  .sort((a, b) => {
    const diff = _eventDate(a) - _eventDate(b);
    if (diff !== 0) return diff;
    // Les fiches annuaire permanentes (spa, musées, cinéma, happy hours…) en dernier pour chaque jour
    const ao = a.pinLast ? 1 : 0;
    const bo = b.pinLast ? 1 : 0;
    if (ao !== bo) return ao - bo;
    return _eventHour(a) - _eventHour(b);
  });
